      DATE: '2025-06-15',
    })

    expect(written).toBe(true)
    const content = readFileSync(targetPath, 'utf-8')
    expect(content).toBe('# Goal v001\nDate: 2025-06-15\n')
  })

  it('skips existing file when force=false', () => {
